sp_widget.client_script:
api.controller=function($scope, $filter, spUtil,spModal) {
  /* widget controller */
  var c = this;
	$scope.showingHistory=false;

	// catch view history click from Scheduled OoO widget
	$scope.$on('$oooViewHistory', function () {
		$scope.showingHistory=true;	
	});	

	$scope.showSchedule = function(){
		$scope.showingHistory=false;		
	};

	$scope.showHistory = function(){
		$scope.showingHistory=true;		
	};

	// *******************************************
	// START NEW OOO MENU OPTION
	// *******************************************
	$scope.newOOO = function(){
		spModal.open({
			message: '',
			backdrop: 'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: c.data.table,
				sys_id: -1,
				query: c.data.newFilter,
				hideRelatedLists: false,
				omitHeader: true,
				bifold: false,
				hideAttachmentBtn: true,
				isModal: true
			},
			shared: {},
			//size: 'lg',
			buttons: [''],
			footerStyle: {
				'display': 'none'
			}
		}).then(function(){
			spUtil.update($scope);
		}, function() {
				spUtil.update($scope);
		});
	};
	// *******************************************
	// END NEW OOO MENU OPTION
	// *******************************************

};

sp_widget.css:
.ooo-flex-container {
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.ooo-back-div-height {
  /* height: 40px; */
  /* DFCT0011552 */
  height: 50px;
  padding-top: 10px;
  padding-left: 20px;
}

.ooo-dnd-width {
  width:166px;
  height:166px;
  margin-left:30px;
}

.ooo-profile-card {
  /* DFCT0011552 padding-left:20px; */
  display: flex;
  flex-direction: row;
  align-items: start;
  justify-content: start;
}

/* DFCT0011552 no longer used
.ooo-header-padding {
  padding-top: 50px;
  padding-bottom: 40px;
}
*/

/* DFCT0011552 */
.ooo-header-padding-page {
  padding: 0 100px 40px 100px;
}

/* DFCT0011552 */
.ooo-header-padding-modal {
  padding: 0 40px 20px 40px;
}

/* DFCT0011552 */
.ooo-padding-top-bottom-page {
  padding: 0 100px 0 100px;
}

/* DFCT0011552 */
.ooo-padding-top-bottom-modal {
  padding: 0 40px 0 40px;
}

/* DFCT0011552 no longer used
.ooo-panel-padding {
  padding-left: 20px;
  padding-right: 20px;
}
*/

.ooo-bottom-padding {
  padding-bottom: 20px;
}

.ooo-24-light {
  font-family:SourceSansPro;
  font-size:24px;
  font-weight:100;
  color:#000000;
}
.ooo-no-active-schedules {
  font-family: SourceSansPro;
  font-size: 16px;
  font-weight: 600;
  color: #000000;
}
.ooo-btn{
  margin-top: 20px;
  color: #FFFFFF;
  font-size: 14px;
  font-weight: 400;
  border-radius: 5px;
  background-color: #00A4FF;
  border-color: #00A4FF;  
  border-style: solid;
  box-shadow: 0px 3px 6px 0px rgba(0,0,0,0.25);
}

.ooo-btn:hover{
  color: #FFFFFF;
  background-color: #0087D2;
  border-color: #0087D2;
}

.ooo-btn:focus{
  color: #FFFFFF;
  background-color: #00A4FF;
  border-color: #0087D2;
}

.ooo-btn:disabled {
  color: #FFFFFF;
  background-color: #757575;
  border-color: #757575;
  cursor: none;
}

.ooo-text{
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #757575;
}

.ooo-backbtn {
  width: 100%;
  height: 30px;
  background-color: none;
  color: black;
  border-radius: 5px;
  box-shadow: none;
  /* DFCT0011552 */
  padding: 5px 10px;
  font-weight: bold;
}
.ooo-backbtn:hover{
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
  cursor: pointer;
}
.ooo-backbtn:focus{
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-hyperlink{
  width: 100%;
  height: 32px;
  background-color: none;
  border-radius: 5px;
  text-decoration: underline;
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #000000;
  font-weight: 400;
  line-height: 28px;
  box-shadow: none;
}

.ooo-hyperlink:hover{
  color: #0087D2;
  cursor: pointer;
}

.ooo-hyperlink:focus{
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-hyperlink:disabled {
  color: #757575;
  cursor: none;
}

/* DFCT0011552 plus hover, focus and disabled */
.ooo-hyperlink-magenta-pink {
  width: 100%;
  height: 32px;
  background-color: none;
  border-radius: 5px;
  text-decoration: underline;
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #92386F;
  font-weight: 400;
  line-height: 28px;
  box-shadow: none;
}

.ooo-hyperlink-magenta-pink:hover {
  color: #0087D2;
  cursor: pointer;
}

.ooo-hyperlink-magenta-pink:focus {
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-hyperlink-magenta-pink:disabled {
  color: #757575;
  cursor: none;
}

/* DFCT0011552 */
.ooo-panel-footer {
  align-items: center;
  background-color: #FFFFFF;
  display: flex;
  height: 55px;
}

